         userDriverDelegate: nil)
+    controller.updater.automaticallyChecksForUpdates = false
+    controller.start()
+    return controller
+}
+#else
+private func makeUpdaterController() -> UpdaterProviding {
+    DisabledUpdaterController()
+}
